import{_ as e,o as a,c as i,a2 as o}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Chapter 11: Git Integration","description":"Version control as a safety net for coding agents, covering git operations, worktree isolation, and repository analysis.","frontmatter":{"title":"Chapter 11: Git Integration","description":"Version control as a safety net for coding agents, covering git operations, worktree isolation, and repository analysis."},"headers":[],"relativePath":"learn/project/11-git-integration/index.md","filePath":"learn/project/11-git-integration/index.md"}'),r={name:"learn/project/11-git-integration/index.md"};function n(s,t,l,c,g,h){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="git-integration" tabindex="-1">Git Integration <a class="header-anchor" href="#git-integration" aria-label="Permalink to &quot;Git Integration&quot;">​</a></h1><p>Version control is the coding agent&#39;s most powerful safety net. When an agent modifies files across a codebase, the ability to track changes, create atomic commits, and roll back mistakes transforms risky operations into reversible experiments. This chapter builds a comprehensive git integration layer that gives your agent the same version control superpowers that experienced developers rely on daily.</p><p>You will implement tools that let the agent inspect repository state through status and diff commands, manage branches for isolated work, and create well-structured commits with meaningful messages. Beyond basic operations, you will build worktree isolation so the agent can work on multiple tasks simultaneously without interference, and repository analysis tools that help the agent understand project history and code ownership.</p><p>By the end of this chapter, your agent will treat git not as an afterthought but as a core part of its workflow -- checking status before making changes, creating checkpoints during complex refactors, and using blame and log data to make better decisions about how to modify code.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Implement git status and diff tools that give the agent awareness of repository state</li><li>Build branch management capabilities for isolated feature work</li><li>Create a commit tool that produces clean, well-messaged commits</li><li>Use worktree isolation to enable parallel agent tasks without conflicts</li><li>Develop repository analysis tools using git log and blame</li><li>Ensure all git operations follow safe, non-destructive patterns</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/project/11-git-integration/01-git-basics-for-agents.html">Git Basics for Agents</a></li><li><a href="/project/11-git-integration/02-git-status-diff.html">Git Status and Diff</a></li><li><a href="/project/11-git-integration/03-branch-management.html">Branch Management</a></li><li><a href="/project/11-git-integration/04-creating-commits.html">Creating Commits</a></li><li><a href="/project/11-git-integration/05-worktree-isolation.html">Worktree Isolation</a></li><li><a href="/project/11-git-integration/06-diff-generation.html">Diff Generation</a></li><li><a href="/project/11-git-integration/07-safe-operations.html">Safe Operations</a></li><li><a href="/project/11-git-integration/08-merge-conflict-detection.html">Merge Conflict Detection</a></li><li><a href="/project/11-git-integration/09-repo-analysis.html">Repo Analysis</a></li><li><a href="/project/11-git-integration/10-log-and-blame.html">Log and Blame</a></li><li><a href="/project/11-git-integration/11-git-tool-implementation.html">Git Tool Implementation</a></li><li><a href="/project/11-git-integration/12-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 4: Tool system fundamentals and the tool trait pattern</li><li>Chapter 5: File operation tools and path handling</li><li>Chapter 6: Shell execution with safety constraints</li></ul>',10)])])}const d=e(r,[["render",n]]);export{m as __pageData,d as default};
